import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { ShieldCheckIcon, PlusIcon, ClockIcon, CheckCircleIcon, XCircleIcon } from '@heroicons/react/24/outline';
import { policyAPI } from '../services/api';
import toast from 'react-hot-toast';

const Policies = () => {
  const [policies, setPolicies] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchPolicies();
  }, []);

  const fetchPolicies = async () => {
    try {
      const response = await policyAPI.getWorkerPolicies();
      setPolicies(response.data.data.policies);
    } catch (error) {
      toast.error('Failed to fetch policies');
    } finally {
      setLoading(false);
    }
  };

  const handleActivatePolicy = async (policyId) => {
    try {
      await policyAPI.activatePolicy(policyId);
      toast.success('Policy activated successfully');
      fetchPolicies();
    } catch (error) {
      toast.error('Failed to activate policy');
    }
  };

  const getStatusIcon = (status) => {
    switch (status) {
      case 'active':
        return <CheckCircleIcon className="h-5 w-5 text-green-600" />;
      case 'pending':
        return <ClockIcon className="h-5 w-5 text-yellow-600" />;
      case 'expired':
      case 'inactive':
        return <XCircleIcon className="h-5 w-5 text-red-600" />;
      default:
        return <ClockIcon className="h-5 w-5 text-gray-600" />;
    }
  };

  const getStatusColor = (status) => {
    switch (status) {
      case 'active':
        return 'bg-green-100 text-green-800';
      case 'pending':
        return 'bg-yellow-100 text-yellow-800';
      case 'expired':
      case 'inactive':
        return 'bg-red-100 text-red-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary-600"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">My Policies</h1>
          <p className="text-gray-600">Manage your insurance policies</p>
        </div>
        <Link
          to="/policies/create"
          className="btn-primary"
        >
          <PlusIcon className="h-5 w-5 mr-2" />
          Create Policy
        </Link>
      </div>

      {policies.length === 0 ? (
        <div className="text-center py-12">
          <ShieldCheckIcon className="mx-auto h-12 w-12 text-gray-400" />
          <h3 className="mt-2 text-sm font-medium text-gray-900">No policies yet</h3>
          <p className="mt-1 text-sm text-gray-500">
            Get started by creating your first insurance policy.
          </p>
          <div className="mt-6">
            <Link
              to="/policies/create"
              className="btn-primary"
            >
              <PlusIcon className="h-5 w-5 mr-2" />
              Create Policy
            </Link>
          </div>
        </div>
      ) : (
        <div className="grid grid-cols-1 gap-6">
          {policies.map((policy) => (
            <div key={policy._id} className="card">
              <div className="card-header">
                <div className="flex items-center justify-between">
                  <div className="flex items-center">
                    {getStatusIcon(policy.status.current)}
                    <h3 className="ml-2 text-lg font-medium text-gray-900">
                      Policy #{policy.policyNumber}
                    </h3>
                  </div>
                  <span className={`badge ${getStatusColor(policy.status.current)}`}>
                    {policy.status.current}
                  </span>
                </div>
              </div>
              <div className="card-content">
                <div className="space-y-4">
                  <div>
                    <h4 className="text-sm font-medium text-gray-900">Coverage Details</h4>
                    <div className="mt-2 space-y-1">
                      <p className="text-sm text-gray-600">
                        Max Payout per Claim: <span className="font-medium">₹{policy.coverage.maxPayoutPerClaim}</span>
                      </p>
                      <p className="text-sm text-gray-600">
                        Max Payout per Week: <span className="font-medium">₹{policy.coverage.maxPayoutPerWeek}</span>
                      </p>
                      <p className="text-sm text-gray-600">
                        Premium: <span className="font-medium">₹{policy.premium.finalAmount}/week</span>
                      </p>
                    </div>
                  </div>

                  <div>
                    <h4 className="text-sm font-medium text-gray-900">Covered Risks</h4>
                    <div className="mt-2 flex flex-wrap gap-2">
                      {policy.coverage.coveredRisks.map((risk, index) => (
                        <span
                          key={index}
                          className={`badge ${risk.isActive ? 'badge-success' : 'badge-warning'}`}
                        >
                          {risk.type.replace('_', ' ')}
                        </span>
                      ))}
                    </div>
                  </div>

                  {policy.status.expiresAt && (
                    <div>
                      <h4 className="text-sm font-medium text-gray-900">Validity</h4>
                      <p className="mt-1 text-sm text-gray-600">
                        Expires: {new Date(policy.status.expiresAt).toLocaleDateString()}
                      </p>
                    </div>
                  )}
                </div>
              </div>
              <div className="card-footer">
                <div className="flex justify-between">
                  <Link
                    to={`/policies/${policy._id}`}
                    className="btn-outline"
                  >
                    View Details
                  </Link>
                  {policy.status.current === 'pending' && (
                    <button
                      onClick={() => handleActivatePolicy(policy._id)}
                      className="btn-success"
                    >
                      Activate
                    </button>
                  )}
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default Policies;
